def calculate_total(items):
    total = 0.0
    for item in items:
        total += item['price']
    return total

def process_order(order_id, items):
    total_price = calculate_total(items)
    order_summary = {
        'order_id': order_id,
        'total': total_price,
        'status': 'processed'
    }
    return order_summary

from src.app import process_order

if __name__ == '__main__':
    valid_items = [
        {'name': 'Laptop', 'price': 1200.00},
        {'name': 'Mouse', 'price': 25.00}
    ]
    order_summary = process_order('ORD-123', valid_items)
    print(f"Successfully processed order: {order_summary}")

